outcomeMeasures:
[{'type': 'PRIMARY', 'title': 'Part 1: Number of Participants With Dose-limiting Toxicities', 'description': 'A dose-limiting toxicity (DLT) was defined as any grade 3 or 4 conatumumab-related or combination (panitumumab and conatumumab)-related adverse event, or grade 3 or 4 laboratory abnormality that occurred during the first 4 weeks (28 days) of treatment with panitumumab and conatumumab. Anemia and lymphopenia were not considered DLTs.

Common Terminology Criteria for Adverse Events (CTCAE) version 3.0 was used to grade all adverse events and toxicities.', 'populationDescription': 'DLT-evaluable patients were those who received ≥ 2 doses of panitumumab and conatumumab as scheduled (ie, weeks 1 and 3) and completed 4 weeks (28 days) of treatment, or had a DLT within the first 4 weeks (28 days) of treatment.', 'reportingStatus': 'POSTED', 'paramType': 'NUMBER', 'unitOfMeasure': 'participants', 'timeFrame': '4 weeks', 'groups': [{'id': 'OG000', 'title': 'Panitumumab Plus Conatumumab', 'description': 'Participants received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '5'}]}], 'classes': [{'categories': [{'measurements': [{'groupId': 'OG000', 'value': '0'}]}]}]}, {'type': 'PRIMARY', 'title': 'Number of Participants With an Objective Response', 'description': 'An overall objective response of either a confirmed complete response or partial response, where the overall objective response was equivalent to the best overall response recorded for each participant from enrollment until disease progression or recurrence. Tumor response was assessed by the investigator according to the modified Response Evaluation Criteria in Solid Tumors (RECIST) version 1.0. Responses were confirmed no less than 4 weeks after the criteria for response were first met. Complete response defined as the disappearance of all target and non-target lesions and no new lesions. Partial response defined as either the disappearance of all target lesions with the persistence of one or more non-target lesion(s), or, at least a 30% decrease in the sum of the longest diameter (SLD) of target lesions, taking as reference the Baseline SLD and the disappearance of all or the persistence of 1 or more non-target lesions.', 'populationDescription': 'Subset of the Safety Analysis Set, composed of all enrolled participants who received at least one dose of study drug who had known Kirsten Rat Sarcoma Virus Oncogene (KRAS) status and Baseline measurable disease.', 'reportingStatus': 'POSTED', 'paramType': 'NUMBER', 'unitOfMeasure': 'participants', 'timeFrame': 'Participants were evaluated for tumor response until radiographic disease progression or until the participant began another anticancer treatment (up to a maximum of 55.6 weeks).', 'groups': [{'id': 'OG000', 'title': 'Wild-type KRAS', 'description': 'Participants with wild-type Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}, {'id': 'OG001', 'title': 'Mutant KRAS', 'description': 'Participants with mutant Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '18'}, {'groupId': 'OG001', 'value': '25'}]}], 'classes': [{'categories': [{'measurements': [{'groupId': 'OG000', 'value': '0'}, {'groupId': 'OG001', 'value': '0'}]}]}]}, {'type': 'SECONDARY', 'title': 'Progression-free Survival', 'description': 'Kaplan-Meier estimate of the median time from enrollment to death from any cause or disease progression. Progressive disease is defined as at least a 20% increase in the sum of the longest diameters (SLD) of target lesions, taking as reference the nadir SLD recorded since the treatment started, or the appearance of one or more new lesions, or the unequivocal progression of existing non-target lesions.', 'populationDescription': 'Subset of the Safety Analysis Set, composed of all enrolled participants who received at least one dose of study drug who had known Kirsten Rat Sarcoma Virus Oncogene (KRAS) status.', 'reportingStatus': 'POSTED', 'paramType': 'MEDIAN', 'dispersionType': '95% Confidence Interval', 'unitOfMeasure': 'weeks', 'timeFrame': 'Participants were evaluated for tumor response until radiographic disease progression or until the participant began another anticancer treatment (up to a maximum of 55.6 weeks).', 'groups': [{'id': 'OG000', 'title': 'Wild-type KRAS', 'description': 'Participants with wild-type Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}, {'id': 'OG001', 'title': 'Mutant KRAS', 'description': 'Participants with mutant Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '19'}, {'groupId': 'OG001', 'value': '25'}]}], 'classes': [{'categories': [{'measurements': [{'groupId': 'OG000', 'value': '10.0', 'lowerLimit': '7.0', 'upperLimit': '23.0'}, {'groupId': 'OG001', 'value': '7.1', 'lowerLimit': '6.7', 'upperLimit': '8.0'}]}]}]}, {'type': 'SECONDARY', 'title': 'Overall Survival', 'description': 'Kaplan-Meier estimate of time from enrollment to death from any cause', 'populationDescription': 'Subset of the Safety Analysis Set, composed of all enrolled participants who received at least one dose of study drug, who had known Kirsten Rat Sarcoma Virus Oncogene (KRAS) status.', 'reportingStatus': 'POSTED', 'paramType': 'MEDIAN', 'dispersionType': '95% Confidence Interval', 'unitOfMeasure': 'months', 'timeFrame': 'Participants were evaluated for tumor response until radiographic disease progression or until the participant began another anticancer treatment (up to a maximum of 55.6 weeks).', 'groups': [{'id': 'OG000', 'title': 'Wild-type KRAS', 'description': 'Participants with wild-type Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}, {'id': 'OG001', 'title': 'Mutant KRAS', 'description': 'Participants with mutant Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '19'}, {'groupId': 'OG001', 'value': '25'}]}], 'classes': [{'categories': [{'measurements': [{'groupId': 'OG000', 'value': '7.3', 'lowerLimit': '3.2', 'upperLimit': '15.0'}, {'groupId': 'OG001', 'value': '4.4', 'lowerLimit': '3.4', 'upperLimit': '8.5'}]}]}]}, {'type': 'SECONDARY', 'title': 'Number of Participants With Disease Control', 'description': 'Disease control defined as participants with an overall objective response of complete response (CR), partial response (PR), or stable disease during the treatment period, assessed by the investigator according to the modified Response Evaluation Criteria in Solid Tumors (RECIST). Responses were confirmed no less than 4 weeks after the criteria for response were first met. CR defined as the disappearance of all target and non-target lesions and no new lesions. PR defined as either the disappearance of all target lesions with the persistence of one or more non-target lesion(s), or, at least a 30% decrease in the sum of the longest diameter (SLD) of target lesions, taking as reference the Baseline SLD and the disappearance of all or the persistence of 1 or more non-target lesions. Stable disease defined as neither sufficient shrinkage to qualify for PR nor sufficient increase to qualify for progressive disease, taking as reference the nadir LD since the treatment started.', 'populationDescription': 'Subset of the Safety Analysis Set, composed of all enrolled participants who received at least one dose of study drug, who had known Kirsten Rat Sarcoma Virus Oncogene (KRAS) status.', 'reportingStatus': 'POSTED', 'paramType': 'NUMBER', 'unitOfMeasure': 'participants', 'timeFrame': 'Participants were evaluated for tumor response until radiographic disease progression or until the participant began another anticancer treatment (up to a maximum of 55.6 weeks).', 'groups': [{'id': 'OG000', 'title': 'Wild-type KRAS', 'description': 'Participants with wild-type Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}, {'id': 'OG001', 'title': 'Mutant KRAS', 'description': 'Participants with mutant Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '19'}, {'groupId': 'OG001', 'value': '25'}]}], 'classes': [{'categories': [{'measurements': [{'groupId': 'OG000', 'value': '8'}, {'groupId': 'OG001', 'value': '4'}]}]}]}, {'type': 'SECONDARY', 'title': 'Time to Response', 'description': 'The interval in days from the first dose of study therapy to the date of first confirmed objective response. Calculated only for participants with an objective response.', 'populationDescription': 'Patients with an overall objective response', 'reportingStatus': 'POSTED', 'timeFrame': 'Participants were evaluated for tumor response until radiographic disease progression or until the participant began another anticancer treatment (up to a maximum of 55.6 weeks).', 'groups': [{'id': 'OG000', 'title': 'Wild-type KRAS', 'description': 'Participants with wild-type Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}, {'id': 'OG001', 'title': 'Mutant KRAS', 'description': 'Participants with mutant Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '0'}, {'groupId': 'OG001', 'value': '0'}]}]}, {'type': 'SECONDARY', 'title': 'Duation of Response', 'description': 'The interval in days from the first confirmed objective response to disease progression per the modified RECIST criteria or death. Calculated only for participants with an objective response.', 'populationDescription': 'Patients with an overall objective response', 'reportingStatus': 'POSTED', 'timeFrame': 'Participants were evaluated for tumor response until radiographic disease progression or until the participant began another anticancer treatment (up to a maximum of 55.6 weeks).', 'groups': [{'id': 'OG000', 'title': 'Wild-type KRAS', 'description': 'Participants with wild-type Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}, {'id': 'OG001', 'title': 'Mutant KRAS', 'description': 'Participants with mutant Kirsten Rat Sarcoma Virus Oncogene (KRAS) received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '0'}, {'groupId': 'OG001', 'value': '0'}]}]}, {'type': 'SECONDARY', 'title': 'Number of Participants With Anti-therapeutic Antibodies', 'description': 'Number of participants with human anti-panitumumab antibodies (HAPA) or anti-conatumumab antibodies measured by immunoassay.', 'populationDescription': 'Safety analysis set, including all randomized patients who received at least 1 dose of investigational product. N indicates the number of patients with immunoassay results at the specified time points.', 'reportingStatus': 'POSTED', 'paramType': 'NUMBER', 'unitOfMeasure': 'participants', 'timeFrame': 'Antibody samples were collected at weeks 1, 7, and 23 and every 6 months thereafter during treatment, and at the safety follow-up and follow-up visits. The mean follow-up time was 35.7 weeks.', 'groups': [{'id': 'OG000', 'title': 'Panitumumab Plus Conatumumab', 'description': 'Participants received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '52'}]}], 'classes': [{'title': 'Anti-panitumumab Antibody at Baseline (N=51)', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '0'}]}]}, {'title': 'Anti-panitumumab Antibody Post-baseline (N=37)', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '2'}]}]}, {'title': 'Anti-conatumumab Antibody at Baseline (N=50)', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Anti-conatumumab Antibody Post-baseline (N=37)', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '0'}]}]}]}, {'type': 'SECONDARY', 'title': 'Number of Participants With Adverse Events (AEs)', 'description': 'An AE is defined as any untoward medical occurrence in a patient or clinical investigation participant administered a pharmaceutical product and that does not necessarily have a causal relationship with this treatment, and includes any such occurrence (eg, sign, symptom, or diagnosis) or worsening of a pre-existing medical condition from the time that a participant has signed informed consent to the time of initiation of investigational product. The severity of AEs was graded using the Common Terminology Criteria for Adverse Events (CTCAE) version 3.0, according to the following:

1. = Mild: Aware of sign or symptom, but easily tolerated
2. = Moderate: Discomfort enough to cause interference with usual activity;
3. = Severe: Incapacitating with inability to work or do usual activity;
4. = Life-threatening: an event in which the patient was, in the view of the investigator, at risk of death at the time of the event;
5. = Fatal.', 'populationDescription': 'Safety Analysis Set, including all randomized patients who received at least one dose of investigational drug.', 'reportingStatus': 'POSTED', 'paramType': 'NUMBER', 'unitOfMeasure': 'participants', 'timeFrame': 'From first dose of investigational drug until 30 days after the last dose, up to a maximum of 50 weeks.', 'groups': [{'id': 'OG000', 'title': 'Panitumumab Plus Conatumumab', 'description': 'Participants received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '52'}]}], 'classes': [{'title': 'Any adverse event', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '51'}]}]}, {'title': 'Grade 3 adverse event', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '16'}]}]}, {'title': 'Grade 4 adverse event', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '4'}]}]}, {'title': 'Grade 5 adverse event', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '6'}]}]}]}, {'type': 'SECONDARY', 'title': 'Number of Participants With Post-baseline Laboratory Values Grade 3 or Higher', 'description': 'Laboratory values were assessed using the National Cancer Institute (NCI) Common Toxicity Criteria (version 3.0) according to the following: 1 = Mild; 2 = Moderate; 3 = Severe; 4 = Life-threatening; 5 = Fatal.', 'populationDescription': 'Safety Analysis Set, including all randomized patients who received at least one dose of investigational drug.', 'reportingStatus': 'POSTED', 'paramType': 'NUMBER', 'unitOfMeasure': 'participants', 'timeFrame': 'From first dose of investigational drug until 30 days after the last dose, up to a maximum of 50 weeks.', 'groups': [{'id': 'OG000', 'title': 'Panitumumab Plus Conatumumab', 'description': 'Participants received 10 mg/kg conatumumab and 6 mg/kg panitumumab administered on the same day by sequential intravenous (IV) infusions once every 2 weeks until progressive disease, intolerability, withdrawal, or death.'}], 'denoms': [{'units': 'Participants', 'counts': [{'groupId': 'OG000', 'value': '52'}]}], 'classes': [{'title': 'Alanine Amino Transferase increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '4'}]}]}, {'title': 'Alkaline Phosphatase increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '9'}]}]}, {'title': 'Amylase increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '2'}]}]}, {'title': 'Aspartate Amino Transferase increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '5'}]}]}, {'title': 'Bicarbonate decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Calcium increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Calcium decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '3'}]}]}, {'title': 'Glucose increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Lipase increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '2'}]}]}, {'title': 'Magnesium decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '4'}]}]}, {'title': 'Magnesium increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Phosphorus decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Sodium decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '1'}]}]}, {'title': 'Total Bilirubin increase', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '6'}]}]}, {'title': 'Absolute Neutrophil Count decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '7'}]}]}, {'title': 'Hemoglobin decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '4'}]}]}, {'title': 'Lymphocytes decrease', 'categories': [{'measurements': [{'groupId': 'OG000', 'value': '7'}]}]}]}]
